// ========================================
// EXTRACT FORM DATA - FINAL VERSION
// Columns từ Google Form:
// [0] Timestamp
// [1] Email Address
// [2] Mã Clarification
// [3] Nguồn chỉ đạo
// [4] Ngày nhận chỉ đạo
// [5] Nội dung chỉ đạo gốc
// [6] Đầu mối thực hiện (T1)
// [7] T2 - Nhiệm vụ (Mô tả chi tiết)
// [8] T3 - Chỉ tiêu (Đo lường kết quả)
// [9] T4 - Thời hạn (Deadline)
// [10] Ghi chú / Thắc mắc
// [11] Xác nhận nhận chỉ đạo
// ========================================

const row = $input.first().json;
const columns = Object.keys(row);

// ========== SMART FIELD DETECTION ==========
const findField = function(keywords, excludeKeywords) {
  excludeKeywords = excludeKeywords || [];
  for (var i = 0; i < columns.length; i++) {
    var col = columns[i];
    var colLC = col.toLowerCase();
    var hasKeyword = false;
    var hasExclude = false;

    for (var j = 0; j < keywords.length; j++) {
      if (colLC.indexOf(keywords[j].toLowerCase()) !== -1) {
        hasKeyword = true;
        break;
      }
    }

    for (var k = 0; k < excludeKeywords.length; k++) {
      if (colLC.indexOf(excludeKeywords[k].toLowerCase()) !== -1) {
        hasExclude = true;
        break;
      }
    }

    if (hasKeyword && !hasExclude) {
      return row[col] || '';
    }
  }
  return '';
};

// ========== EXTRACT FIELDS ==========
var timestamp = row['Timestamp'] || row['Dấu thời gian'] || '';
var email = row['Email Address'] || row['Địa chỉ email'] || '';

// Clarification ID
var clarificationId = findField(['mã clarification', 'clarification id', 'mã chỉ đạo']);

// Form fields
var nguonChiDao = findField(['nguồn chỉ đạo', 'nguồn']);
var ngayNhanChiDao = findField(['ngày nhận']);
var noiDungChiDaoGoc = findField(['nội dung chỉ đạo gốc', 'nội dung chỉ đạo']);
var dauMoiT1 = findField(['đầu mối', 't1']);
var t2NhiemVu = findField(['t2', 'nhiệm vụ']);
var t3ChiTieu = findField(['t3', 'chỉ tiêu']);
var t4ThoiHanRaw = findField(['t4', 'thời hạn', 'deadline']);
var ghiChu = findField(['ghi chú', 'thắc mắc']);
var xacNhanRaw = findField(['xác nhận']);

// ========== PARSE BOOLEAN ==========
var xacNhanDoc = false;
var camKetThucHien = false;

if (xacNhanRaw) {
  var xacNhanLC = xacNhanRaw.toString().toLowerCase();
  xacNhanDoc = xacNhanLC.indexOf('xác nhận') !== -1 || xacNhanLC.indexOf('đã hiểu') !== -1;
  camKetThucHien = xacNhanLC.indexOf('cam kết') !== -1;
}

// ========== CONVERT DATE: MM/DD/YYYY -> YYYY-MM-DD ==========
var t4ThoiHan = t4ThoiHanRaw;
if (t4ThoiHanRaw && t4ThoiHanRaw.indexOf('/') !== -1) {
  var parts = t4ThoiHanRaw.split('/');
  if (parts.length === 3) {
    var month = parts[0].length === 1 ? '0' + parts[0] : parts[0];
    var day = parts[1].length === 1 ? '0' + parts[1] : parts[1];
    var year = parts[2];
    t4ThoiHan = year + '-' + month + '-' + day;
  }
}

// ========== VALIDATE 4T (MUST BE BOOLEAN!) ==========
var has4T = Boolean(noiDungChiDaoGoc && t2NhiemVu && t3ChiTieu && t4ThoiHan);
var isConfirmed = Boolean(xacNhanDoc || camKetThucHien);
var hasId = Boolean(clarificationId && clarificationId.length > 10);

console.log('=== VALIDATION ===');
console.log('Nội dung:', noiDungChiDaoGoc ? 'OK' : 'MISSING');
console.log('T2:', t2NhiemVu ? 'OK' : 'MISSING');
console.log('T3:', t3ChiTieu ? 'OK' : 'MISSING');
console.log('T4:', t4ThoiHan ? 'OK' : 'MISSING');
console.log('has4T:', has4T, typeof has4T);
console.log('isConfirmed:', isConfirmed, typeof isConfirmed);
console.log('hasId:', hasId, typeof hasId);
console.log('clarificationId:', clarificationId);

return {
  // Metadata
  timestamp: timestamp,
  email: email || 'hoangkha@esuhai.com',
  clarificationId: clarificationId.toString().trim(),

  // Task data (matching Notion field names)
  noiDungChiDaoGoc: noiDungChiDaoGoc,
  dauMoiT1: dauMoiT1,
  t2NhiemVu: t2NhiemVu,
  t3ChiTieu: t3ChiTieu,
  t4ThoiHan: t4ThoiHan,
  nguonChiDao: nguonChiDao,
  ghiChu: ghiChu,

  // Confirmation
  xacNhanDoc: xacNhanDoc,
  camKetThucHien: camKetThucHien,

  // Validation flags (BOOLEAN)
  has4T: has4T,
  isConfirmed: isConfirmed,
  hasId: hasId,
  isValid: has4T && isConfirmed && hasId
};

